SELECT TO_CHAR(PERSON_NO) AS APPLY_NO, 'PERSONAL' AS APPLY_TABLE_TYPE, PERSON_ID, TO_CHAR(CREATE_DATE, 'YYYY/MM/DD') AS CREATE_DATE, ACTIVITY, APPLY_TYPE, CREATED_BY AS MANAGER_INFO, NULL AS CALLBACK, NULL AS EARROR FROM HR_PERSONAL_INFO_APPLY WHERE PERSON_ID = #{personId, jdbcType=VARCHAR}
AND CREATE_DATE >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND CREATE_DATE <= TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD') + 1
AND ACTIVITY = #{activitySearch, jdbcType=NUMERIC}
UNION ALL SELECT TO_CHAR(ADDRESS_NO) AS APPLY_NO, 'ADDRESS' AS APPLY_TABLE_TYPE, PERSON_ID, TO_CHAR(CREATE_DATE, 'YYYY/MM/DD') AS CREATE_DATE, ACTIVITY, APPLY_TYPE, CREATED_BY AS MANAGER_INFO, CALLBACK, EARROR FROM HR_ADDRESS_MATTERS_APPLY WHERE PERSON_ID = #{personId, jdbcType=VARCHAR}
AND CREATE_DATE >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND CREATE_DATE <= TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD') + 1
AND ACTIVITY = #{activitySearch, jdbcType=NUMERIC}
