SELECT * FROM (
    SELECT A.*, ROWNUM AS RN FROM (
        SELECT * FROM (

        ) ORDER BY CREATE_DATE DESC, APPLY_NO DESC
    ) A WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC}
) WHERE RN > #{start, jdbcType=NUMERIC}
